message("Saving figures …")

ggsave("fig1_overview.pdf", fig1, width = 12, height = 16)
ggsave("fig1_overview.png", fig1, width = 16, height = 20, dpi = 150)

# Per-rank fig2 (pies) and fig3 (top-taxa bars)
for (rk in PLOT_RANKS) {
  rk_lower <- tolower(rk)
  ggsave(sprintf("fig2_pies_%s.pdf", rk_lower), fig2_list[[rk]], width = 16, height = 14)
  ggsave(sprintf("fig2_pies_%s.png", rk_lower), fig2_list[[rk]], width = 16, height = 14, dpi = 150)
  ggsave(sprintf("fig3_top_%s.pdf",  rk_lower), fig3_list[[rk]], width = 16, height = ifelse(rk_lower %in% c("genus","family"),14,ifelse(rk_lower %in% c("order"),11,ifelse(rk_lower %in% c("class"),7,4))))
  ggsave(sprintf("fig3_top_%s.png",  rk_lower), fig3_list[[rk]], width = 16, height = 14, dpi = 150)
  ggsave(sprintf("fig4_venn_%s.pdf", rk_lower), fig4_list[[rk]], width = 10, height =  9)
  ggsave(sprintf("fig4_venn_%s.png", rk_lower), fig4_list[[rk]], width = 10, height =  9, dpi = 150)
  message(sprintf("  Saved fig2/fig3/fig4 for rank: %s", rk))
}

