cat("\n", strrep("═", 72), "\n", sep = "")
cat("  mcrA DATABASE COMPARISON — 5 Databases\n")
cat(strrep("═", 72), "\n\n", sep = "")

cat("  Database sizes:\n")
for (db in DB_ORDER)
  cat(sprintf("    %-22s : %s sequences  |  %s unique paths\n",
              db, comma(n_seqs_vec[db]), comma(n_uniq_vec[db])))

cat("\n  ── Unique named taxa per rank ", rule, "\n", sep = "")
cat(sprintf("  %-10s", "Rank"))
for (db in DB_ORDER) cat(sprintf("  %15s", db))
cat("\n")
cat(sprintf("  %-10s", strrep("─",10)))
for (db in DB_ORDER) cat(sprintf("  %15s", strrep("─",14)))
cat("\n")
for (r in RANKS) {
  cat(sprintf("  %-10s", r))
  for (db in DB_ORDER) {
    v <- breadth_all %>% filter(rank == r, db == !!db) %>% pull(n_unique)
    cat(sprintf("  %15s", if (length(v) > 0) comma(v[1]) else "—"))
  }
  cat("\n")
}

cat("\n  ── Genus overlap with Yang et al. 2014 ", rule, "\n", sep = "")
cat(sprintf("  %-22s  %8s  %10s  %10s\n",
            "Database", "Shared", "DB-only", "Yang-only"))
for (i in seq_len(nrow(overlap_vs_yang))) {
  r <- overlap_vs_yang[i, ]
  cat(sprintf("  %-22s  %8s  %10s  %10s\n",
              as.character(r$db),
              comma(r$n_shared), comma(r$n_db_only), comma(r$n_yang_only)))
}

