  cat(sprintf("    fig3_top_%s.pdf / .png\n",  rk_lower))
  cat(sprintf("    fig4_venn_%s.pdf / .png\n", rk_lower))
  cat(sprintf("    fig5_heatmap_%s.pdf\n",     rk_lower))
}
cat("    fig4_venn_all_ranks.pdf / .png\n")
